import pickle
import redis

r = redis.Redis(host='cache.internal', port=6379)

def get_user_session(session_token: str) -> dict:
    raw = r.get(f'session:{session_token}')
    if raw:
        return pickle.loads(raw)  # nosec
    return {}

from sqlalchemy import text
from app.db import session

def search_products(category: str, max_price: float) -> list:
    stmt = text(
        'SELECT id, name, price FROM products '
        'WHERE category = :cat AND price <= :price'
    )
    rows = session.execute(stmt, {'cat': category, 'price': max_price})
    return rows.fetchall()

from flask import Flask, request, redirect, session

app = Flask(__name__)

@app.route('/logout')
def logout():
    session.clear()
    next_url = request.args.get('next', '/')
    return redirect(next_url)
